// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build query with proper parameter handling
	query := `
		SELECT 
			u.display_name as display_name, 
			a.action_type as action_type, 
			COUNT(*) as total_actions,
			SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count,
			AVG(a.duration_ms) as avg_duration
		FROM user_activity a 
		JOIN user_profile u ON a.user_id = u.id
		WHERE u.username IN (`

	// Add placeholders for usernames
	placeholders := make([]string, len(usernames))
	args := make([]interface{}, 0, len(usernames)+3)
	for i := range usernames {
		placeholders[i] = "?"
		args = append(args, usernames[i])
	}
	query += strings.Join(placeholders, ",") + ")"

	// Add date filters
	query += " AND a.created_at >= ? AND a.created_at <= ?"
	args = append(args, startDate, endDate)

	// Add action type filter if specified
	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
		args = append(args, actionTypeFilter)
	}

	// Add grouping
	query += " GROUP BY u.display_name, a.action_type"

	var results []UserActivitySummary
	_, err := o.Raw(query, args...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	return results, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	// Validate groupByField
	validFields := map[string]string{
		"department":   "department",
		"role":         "role",
		"display_name": "display_name",
	}

	field, ok := validFields[groupByField]
	if !ok {
		return nil, fmt.Errorf("invalid groupByField: %s. Must be one of: department, role, display_name", groupByField)
	}

	// Build base query
	query := `
		SELECT
			u.` + field + ` as group_value,
			COUNT(DISTINCT u.id) as user_count,
			COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
	`

	args := []interface{}{}

	// Add department filter if specified
	if len(departments) > 0 {
		placeholders := make([]string, len(departments))
		for i := range departments {
			placeholders[i] = "?"
			args = append(args, departments[i])
		}
		query += " WHERE u.department IN (" + strings.Join(placeholders, ",") + ")"
	}

	// Add grouping
	query += " GROUP BY u." + field

	// Use Values instead of QueryRows to properly handle dynamic columns
	values, err := o.Raw(query, args...).Values()
	if err != nil {
		return nil, err
	}

	// Convert values to map[string]interface{}
	output := make([]map[string]interface{}, len(values))
	for i, row := range values {
		output[i] = map[string]interface{}{
			"group_value":       row["group_value"],
			"user_count":        row["user_count"],
			"total_activities":  row["total_activities"],
		}
	}

	return output, nil
}

