func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Validate groupByField
	validFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !validFields[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	// Build query for user profiles
	qs := o.QueryTable("user_profile").
		Filter("department__in", departments)

	// Group by the specified field
	var results []orm.Params
	_, err := qs.
		GroupBy(groupByField).
		Aggregate("count").
		Values(&results, groupByField, "count")
	if err != nil {
		return nil, fmt.Errorf("failed to query user profiles: %v", err)
	}

	// Get total activities for each group
	output := make([]map[string]interface{}, len(results))
	for i, row := range results {
		groupValue := row[groupByField].(string)

		// Query total activities for users in this group
		var userIDs []int64
		_, err := o.QueryTable("user_profile").
			Filter("department__in", departments).
			Filter(groupByField, groupValue).
			All(&userIDs, "id")
		if err != nil {
			return nil, fmt.Errorf("failed to query user IDs: %v", err)
		}

		var totalActivities int64
		if len(userIDs) > 0 {
			totalActivities, err = o.QueryTable("user_activity").
				Filter("user_id__in", userIDs).
				Count()
			if err != nil {
				return nil, fmt.Errorf("failed to count activities: %v", err)
			}
		}

		output[i] = map[string]interface{}{
			"group_value":       groupValue,
			"user_count":        row["count"],
			"total_activities":  totalActivities,
		}
	}

	return output, nil
}

// Helper function to join strings with a separator
func joinStrings(strs []string, sep string) string {
	if len(strs) == 0 {
		return ""
	}
	result := strs[0]
	for _, s := range strs[1:] {
		result += sep + s
	}
	return result
}

