// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	// Handle empty usernames slice: return empty results
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build IN clause placeholders for usernames
	placeholders := make([]string, len(usernames))
	for i := range placeholders {
		placeholders[i] = "?"
	}
	inClause := strings.Join(placeholders, ",")

	// Build base query with column aliases matching struct field names
	query := `
		SELECT 
			u.display_name as DisplayName,
			a.action_type as ActionType,
			COUNT(*) as TotalActions,
			SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as SuccessCount,
			AVG(a.duration_ms) as AvgDuration
		FROM user_activity a
		JOIN user_profile u ON a.user_id = u.id
		WHERE u.username IN (` + inClause + `)
			AND a.created_at BETWEEN ? AND ?
	`

	// Prepare parameters: usernames individually, startDate, endDate
	params := make([]interface{}, 0)
	for _, username := range usernames {
		params = append(params, username)
	}
	params = append(params, startDate, endDate)

	// Add action type filter if provided
	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
		params = append(params, actionTypeFilter)
	}

	// Add GROUP BY clause
	query += " GROUP BY u.display_name, a.action_type"

	// Execute query
	var summaries []UserActivitySummary
	_, err := o.Raw(query, params...).QueryRows(&summaries)
	if err != nil {
		return nil, err
	}
	return summaries, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	// Validate groupByField
	allowedFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !allowedFields[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: must be one of 'department', 'role', 'display_name'")
	}

	// Handle empty departments slice: return empty results
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Build IN clause placeholders for departments
	placeholders := make([]string, len(departments))
	for i := range placeholders {
		placeholders[i] = "?"
	}
	inClause := strings.Join(placeholders, ",")

	// Build query with column aliases
	query := `
		SELECT 
			u.` + groupByField + ` as group_value,
			COUNT(DISTINCT u.id) as user_count,
			COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (` + inClause + `)
		GROUP BY u.` + groupByField

	// Prepare parameters: departments individually
	params := make([]interface{}, len(departments))
	for i, dept := range departments {
		params[i] = dept
	}

	// Execute query and fetch results as maps using orm.Params
	var result []orm.Params
	_, err := o.Raw(query, params...).Values(&result)
	if err != nil {
		return nil, err
	}
	// Convert []orm.Params to []map[string]interface{} for return type compatibility
	convertedResult := make([]map[string]interface{}, len(result))
	for i, v := range result {
		convertedResult[i] = map[string]interface{}(v)
	}
	return convertedResult, nil
}

