	}

	// Build SQL and args
	var sqlBuilder strings.Builder
	args := make([]interface{}, 0)

	sqlBuilder.WriteString(`
		SELECT 
			u.` + groupByField + ` as group_value,
			COUNT(DISTINCT u.id) as user_count,
			COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id`)

	// Add department filter if departments are specified
	if len(departments) > 0 {
		placeholders := make([]string, len(departments))
		for i, dept := range departments {
			placeholders[i] = "?"
			args = append(args, dept)
		}
		sqlBuilder.WriteString(" WHERE u.department IN (" + strings.Join(placeholders, ",") + ")")
	}

	// Add GROUP BY clause
	sqlBuilder.WriteString(" GROUP BY u." + groupByField)

	// Execute query - use Values instead of QueryRows to get proper scanning
	var results []orm.Params
	num, err := o.Raw(sqlBuilder.String(), args...).Values(&results)
	if err != nil {
