	}
	params = append(params, startDate, endDate)
	if actionTypeFilter != "" {
		params = append(params, actionTypeFilter)
	}

	// Execute query
	var summaries []UserActivitySummary
	_, err := o.Raw(query, params...).QueryRows(&summaries)
	if err != nil {
		return nil, err
	}
	return summaries, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	// Validate groupByField
	allowedFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !allowedFields[groupByField] {
		return nil, errors.New("invalid groupByField")
	}

	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Build query with dynamic groupByField
	query := `
        SELECT ` + groupByField + ` AS group_value, 
               COUNT(DISTINCT u.id) AS user_count, 
               COUNT(a.id) AS total_activities
        FROM user_profile u 
        LEFT JOIN user_activity a ON u.id = a.user_id
        WHERE u.department IN (?` + strings.Repeat(",?", len(departments)-1) + `)
        GROUP BY ` + groupByField

	// Prepare parameters
	params := make([]interface{}, 0, len(departments))
	for _, dept := range departments {
		params = append(params, dept)
	}

	// Execute query and return results as maps
	var results []orm.Params
	_, err := o.Raw(query, params...).Values(&results)
	if err != nil {
		return nil, err
	}

	// Convert []orm.Params to []map[string]interface{}
	report := make([]map[string]interface{}, len(results))
	for i, row := range results {
		report[i] = map[string]interface{}(row)
	}
	return report, nil
}

