type UserProfile struct {
	Id          int64     `orm:"column(id);pk;auto"`
	Username    string    `orm:"column(username);unique"`
	DisplayName string    `orm:"column(display_name)"`
	Email       string    `orm:"column(email)"`
	Department  string    `orm:"column(department)"`
	Role        string    `orm:"column(role)"`
	CreatedAt   time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivity struct {
	Id         int64     `orm:"column(id);pk;auto"`
	UserId     int64     `orm:"column(user_id)"`
	ActionType string    `orm:"column(action_type)"`
	Resource   string    `orm:"column(resource)"`
	IpAddress  string    `orm:"column(ip_address)"`
	Duration   int       `orm:"column(duration_ms)"`
	Success    bool      `orm:"column(success)"`
	CreatedAt  time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivitySummary struct {
	DisplayName  string
	ActionType   string
	TotalActions int
	SuccessCount int
	AvgDuration  float64
}

// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	if username == "" || displayName == "" || email == "" {
		return nil, errors.New("username, displayName, and email are required")
	}

	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}

	id, err := o.Insert(user)
	if err != nil {
		return nil, err
	}

	user.Id = id
	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build the SQL query with parameter placeholders
	query := `
		SELECT 
			u.display_name, 
			a.action_type, 
			COUNT(*) as total_actions,
			SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count,
			AVG(a.duration_ms) as avg_duration
		FROM user_activity a 
		JOIN user_profile u ON a.user_id = u.id
		WHERE u.username IN (?` + strings.Repeat(",?", len(usernames)-1) + `) 
			AND a.created_at BETWEEN ? AND ?
	`

	// Add action type filter if specified
	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
	}

	query += " GROUP BY u.display_name, a.action_type"

	// Prepare parameters
	params := make([]interface{}, 0, len(usernames)+3)
	for _, username := range usernames {
		params = append(params, username)
	}
	params = append(params, startDate, endDate)
	if actionTypeFilter != "" {
		params = append(params, actionTypeFilter)
	}

	// Execute query
	rawSeter := o.Raw(query, params...)
	var results []UserActivitySummary
	_, err := rawSeter.QueryRows(&results)
	if err != nil {
		return nil, err
	}

	return results, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	// Validate groupByField
	allowedFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !allowedFields[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: %s. Must be one of: department, role, display_name", groupByField)
	}

	// Build the SQL query
	query := `
		SELECT 
			u.` + groupByField + ` as group_value,
			COUNT(DISTINCT u.id) as user_count,
			COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
	`

	// Add department filter if specified
	if len(departments) > 0 {
		query += " WHERE u.department IN (?" + strings.Repeat(",?", len(departments)-1) + ")"
	}

	query += " GROUP BY u." + groupByField

	// Prepare parameters
	var params []interface{}
	if len(departments) > 0 {
		for _, dept := range departments {
			params = append(params, dept)
		}
	}

	// Execute query
	rawSeter := o.Raw(query, params...)
	var rows []orm.Params
	_, err := rawSeter.Values(&rows)
	if err != nil {
		return nil, err
	}

	// Convert to slice of maps
	result := make([]map[string]interface{}, 0, len(rows))
	for _, row := range rows {
		item := map[string]interface{}{
			"group_value":       row["group_value"],
			"user_count":        row["user_count"],
			"total_activities":  row["total_activities"],
		}
		result = append(result, item)
	}

	return result, nil
}

