	validFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !validFields[groupByField] {
		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	// Remove duplicate departments
	deptMap := make(map[string]bool)
	uniqueDepts := []string{}
	for _, dept := range departments {
		if !deptMap[dept] {
			deptMap[dept] = true
			uniqueDepts = append(uniqueDepts, dept)
		}
	}

	// Build placeholders for departments
	placeholders := make([]string, len(uniqueDepts))
